            console.error('Meta API Error (Pages):', data);
            throw new Error(data.error?.message || 'Failed to list pages');
        }

        return new Response(JSON.stringify({ pages: data.data || [] }), {
            headers: { ...corsHeaders, 'Content-Type': 'application/json' },
            status: 200
        });

    } catch (error) {
        console.error('List pages error:', error);
        return new Response(JSON.stringify({ error: String(error) }), {
            headers: { ...corsHeaders, 'Content-Type': 'application/json' },
            status: 400
        });
    }
});

import "jsr:@supabase/functions-js/edge-runtime.d.ts";
import { createClient } from "jsr:@supabase/supabase-js@2";

const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
};

interface MetaTokenResponse {
  access_token: string;
  token_type: string;
  expires_in: number;
}

interface MetaAdAccount {
  id: string;
  name: string;
  account_id: string;
  account_status: number;
  currency: string;
  timezone_name: string;
}

Deno.serve(async (req: Request) => {
  // Handle CORS preflight
  if (req.method === "OPTIONS") {
    return new Response(null, { headers: corsHeaders });
  }

  try {
    const url = new URL(req.url);
    const code = url.searchParams.get("code");
    const state = url.searchParams.get("state");
    const error = url.searchParams.get("error");
    const errorDescription = url.searchParams.get("error_description");

    // Handle OAuth errors
    if (error) {
      console.error("OAuth error:", error, errorDescription);
      return new Response(
        JSON.stringify({ error, error_description: errorDescription }),
        { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    // Validate required params
    if (!code || !state) {
      return new Response(
        JSON.stringify({ error: "Missing code or state parameter" }),
        { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    // Parse state (contains user_id and company_id)
    let stateData: { user_id: string; company_id: string; redirect_url: string };
    try {
      stateData = JSON.parse(atob(state));
    } catch {
      return new Response(
        JSON.stringify({ error: "Invalid state parameter" }),
        { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    // Get Meta App credentials from environment
    const META_APP_ID = Deno.env.get("META_APP_ID");
    const META_APP_SECRET = Deno.env.get("META_APP_SECRET");
    const SUPABASE_URL = Deno.env.get("SUPABASE_URL");
    const SUPABASE_SERVICE_ROLE_KEY = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");

    if (!META_APP_ID || !META_APP_SECRET) {
      console.error("Meta App credentials not configured");
      return new Response(
        JSON.stringify({ error: "Meta App not configured" }),
        { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    // Exchange code for access token
    const redirectUri = `${SUPABASE_URL}/functions/v1/meta-oauth-callback`;
    const tokenUrl = `https://graph.facebook.com/v24.0/oauth/access_token?client_id=${META_APP_ID}&redirect_uri=${encodeURIComponent(redirectUri)}&client_secret=${META_APP_SECRET}&code=${code}`;

    const tokenResponse = await fetch(tokenUrl);
    const tokenData: MetaTokenResponse = await tokenResponse.json();

    if (!tokenResponse.ok || !tokenData.access_token) {
      console.error("Failed to exchange code for token:", tokenData);
      return new Response(
        JSON.stringify({ error: "Failed to get access token" }),
        { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    // Exchange short-lived token for long-lived token
    const longLivedUrl = `https://graph.facebook.com/v24.0/oauth/access_token?grant_type=fb_exchange_token&client_id=${META_APP_ID}&client_secret=${META_APP_SECRET}&fb_exchange_token=${tokenData.access_token}`;

    const longLivedResponse = await fetch(longLivedUrl);
    const longLivedData: MetaTokenResponse = await longLivedResponse.json();

    const accessToken = longLivedData.access_token || tokenData.access_token;
    const expiresIn = longLivedData.expires_in || tokenData.expires_in;

    // Fetch ad accounts
    const adAccountsUrl = `https://graph.facebook.com/v24.0/me/adaccounts?fields=id,name,account_id,account_status,currency,timezone_name&access_token=${accessToken}`;
    const adAccountsResponse = await fetch(adAccountsUrl);
    const adAccountsData = await adAccountsResponse.json();

    if (!adAccountsResponse.ok) {
      console.error("Failed to fetch ad accounts:", adAccountsData);
      return new Response(
        JSON.stringify({ error: "Failed to fetch ad accounts" }),
        { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    const adAccounts: MetaAdAccount[] = adAccountsData.data || [];

    // Initialize Supabase client
    const supabase = createClient(
      SUPABASE_URL!,
      SUPABASE_SERVICE_ROLE_KEY!
    );

    // Calculate token expiration
    const tokenExpiresAt = new Date(Date.now() + expiresIn * 1000).toISOString();

    // Save each ad account as an integration
    const integrations = [];
    for (const account of adAccounts) {
      const { data: integration, error: insertError } = await supabase
        .from("integrations")
        .upsert({
          company_id: stateData.company_id,
          user_id: stateData.user_id,
          platform: "meta",
          account_id: account.account_id,
          account_name: account.name,
          access_token: accessToken,
          token_expires_at: tokenExpiresAt,
          status: account.account_status === 1 ? "active" : "inactive",
          permissions: {
            currency: account.currency,
            timezone: account.timezone_name,
            account_status: account.account_status
          }
        }, {
          onConflict: "company_id,account_id",
          ignoreDuplicates: false
        })
        .select()
        .single();

      if (insertError) {
        console.error("Error saving integration:", insertError);
      } else {
        integrations.push(integration);
      }
    }

    // Save OAuth session
    const sessionId = crypto.randomUUID();
    await supabase.from("oauth_sessions").insert({
      id: sessionId,
      user_id: stateData.user_id,
      access_token: accessToken,
      accounts: adAccounts.map(a => ({ id: a.account_id, name: a.name })),
      expires_at: tokenExpiresAt
    });

    // Redirect back to the app
    const redirectUrl = new URL(stateData.redirect_url || "/integracoes");
    redirectUrl.searchParams.set("success", "true");
    redirectUrl.searchParams.set("accounts", adAccounts.length.toString());

    return new Response(null, {
      status: 302,
      headers: {
        ...corsHeaders,
        Location: redirectUrl.toString()
      }
    });

  } catch (error) {
    console.error("Unexpected error:", error);
    return new Response(
      JSON.stringify({ error: "Internal server error" }),
      { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  }
});

