import "jsr:@supabase/functions-js/edge-runtime.d.ts";
import { createClient } from "jsr:@supabase/supabase-js@2";

const META_API_VERSION = "v24.0";
const META_API_BASE = `https://graph.facebook.com/${META_API_VERSION}`;

const corsHeaders = {
    "Access-Control-Allow-Origin": "*",
    "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
};

interface SyncRequest {
    integration_id?: string;
    company_id?: string;
    sync_type?: "full" | "metrics_only";
}

interface MetaCampaign {
    id: string;
    name: string;
    objective: string;
    status: string;
    daily_budget?: string;
    lifetime_budget?: string;
    start_time?: string;
    stop_time?: string;
    bid_strategy?: string;
    buying_type?: string;
    smart_promotion_type?: string;
    effective_status?: string;
    budget_remaining?: string;
    spend_cap?: string;
    created_time?: string;
}

interface MetaAdSet {
    id: string;
    name: string;
    campaign_id: string;
    status: string;
    daily_budget?: string;
    lifetime_budget?: string;
    bid_strategy?: string;
    targeting?: Record<string, unknown>;
    start_time?: string;
    end_time?: string;
    optimization_goal?: string;
    billing_event?: string;
    destination_type?: string;
    learning_stage_info?: { status: string };
    effective_status?: string;
}

interface MetaAd {
    id: string;
    name: string;
    adset_id: string;
    status: string;
    creative?: {
        id: string;
        title?: string;
        body?: string;
        image_url?: string;
        video_id?: string;
        thumbnail_url?: string;
        call_to_action_type?: string;
    };
}

interface MetaInsight {
    campaign_id?: string;
    date_start: string;
    impressions: string;
    clicks: string;
    spend: string;
    ctr?: string;
    cpc?: string;
    cpm?: string;
    conversions?: string;
    actions?: Array<{ action_type: string; value: string }>;
    reach?: string;
    frequency?: string;
    unique_clicks?: string;
    unique_ctr?: string;
    quality_ranking?: string;
    engagement_rate_ranking?: string;
    conversion_rate_ranking?: string;
    video_p25_watched_actions?: Array<{ value: string }>;
    video_p50_watched_actions?: Array<{ value: string }>;
    video_p75_watched_actions?: Array<{ value: string }>;
    video_p100_watched_actions?: Array<{ value: string }>;
    website_purchase_roas?: Array<{ value: string }>;
}

Deno.serve(async (req: Request) => {
    if (req.method === "OPTIONS") {
        return new Response(null, { headers: corsHeaders });
    }

    try {
        const SUPABASE_URL = Deno.env.get("SUPABASE_URL")!;
        const SUPABASE_SERVICE_ROLE_KEY = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!;
        const supabase = createClient(SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY);

        // Parse request
        const body: SyncRequest = await req.json().catch(() => ({}));
        const { integration_id, company_id, sync_type = "full" } = body;

        // Get integrations to sync
        let query = supabase
            .from("integrations")
            .select("*")
            .eq("platform", "meta")
            .eq("status", "active");

        if (integration_id) {
            query = query.eq("id", integration_id);
        } else if (company_id) {
            query = query.eq("company_id", company_id);
        }

        const { data: integrations, error: intError } = await query;

        if (intError || !integrations?.length) {
            return new Response(
                JSON.stringify({ error: "No integrations found", details: intError }),
                { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
            );
        }

        const results = [];

        for (const integration of integrations) {
            const syncStartTime = new Date().toISOString();
            let itemsSynced = 0;
            let itemsFailed = 0;

            try {
                const accessToken = integration.access_token;
                const accountId = `act_${integration.account_id}`;

                // 1. Fetch campaigns
                if (sync_type === "full") {
                    const campaignsUrl = `${META_API_BASE}/${accountId}/campaigns?fields=id,name,objective,status,daily_budget,lifetime_budget,start_time,stop_time,bid_strategy,buying_type,smart_promotion_type,effective_status,budget_remaining,spend_cap,created_time&limit=100&access_token=${accessToken}`;
                    const campaignsRes = await fetch(campaignsUrl);
                    const campaignsData = await campaignsRes.json();

                    if (campaignsData.data) {
                        for (const campaign of campaignsData.data as MetaCampaign[]) {
                            // Determine Advantage+ state based on smart_promotion_type
                            let advantageState = null;
                            if (campaign.smart_promotion_type === 'SMART_APP_PROMOTION') advantageState = 'advantage_plus_app';
                            else if (campaign.smart_promotion_type === 'GUIDED_CREATION') advantageState = 'advantage_plus_sales';

                            const { error: campError } = await supabase
                                .from("campaigns")
                                .upsert({
                                    company_id: integration.company_id,
                                    integration_id: integration.id,
                                    external_id: campaign.id,
                                    name: campaign.name,
                                    platform: "meta",
                                    status: campaign.status.toLowerCase(),
                                    objective: campaign.objective,
                                    daily_budget: campaign.daily_budget ? parseFloat(campaign.daily_budget) / 100 : null,
                                    lifetime_budget: campaign.lifetime_budget ? parseFloat(campaign.lifetime_budget) / 100 : null,
                                    bid_strategy: campaign.bid_strategy,
                                    start_time: campaign.start_time,
                                    end_time: campaign.stop_time,
                                    buying_type: campaign.buying_type,
                                    advantage_state: advantageState,
                                    effective_status: campaign.effective_status,
                                    budget_remaining: campaign.budget_remaining ? parseFloat(campaign.budget_remaining) / 100 : null,
                                    spend_cap: campaign.spend_cap ? parseFloat(campaign.spend_cap) / 100 : null,
                                    created_time: campaign.created_time,
                                    updated_at: new Date().toISOString()
                                }, { onConflict: "company_id,external_id" });

                            if (campError) {
                                console.error("Campaign upsert error:", campError);
                                itemsFailed++;
                            } else {
                                itemsSynced++;
                            }
                        }
                    }

                    // 2. Fetch ad sets for each campaign
                    const { data: localCampaigns } = await supabase
                        .from("campaigns")
                        .select("id, external_id")
                        .eq("company_id", integration.company_id)
                        .eq("platform", "meta");

                    for (const localCampaign of localCampaigns || []) {
                        const adSetsUrl = `${META_API_BASE}/${localCampaign.external_id}/adsets?fields=id,name,campaign_id,status,daily_budget,lifetime_budget,bid_strategy,targeting,start_time,end_time,optimization_goal,billing_event,destination_type,learning_stage_info,effective_status&limit=100&access_token=${accessToken}`;
                        const adSetsRes = await fetch(adSetsUrl);
                        const adSetsData = await adSetsRes.json();

                        if (adSetsData.data) {
                            for (const adSet of adSetsData.data as MetaAdSet[]) {
                                const { error: adSetError } = await supabase
                                    .from("ad_sets")
                                    .upsert({
                                        company_id: integration.company_id,
                                        campaign_id: localCampaign.id,
                                        external_id: adSet.id,
                                        name: adSet.name,
                                        platform: "meta",
                                        status: adSet.status.toLowerCase(),
                                        daily_budget: adSet.daily_budget ? parseFloat(adSet.daily_budget) / 100 : null,
                                        lifetime_budget: adSet.lifetime_budget ? parseFloat(adSet.lifetime_budget) / 100 : null,
                                        bid_strategy: adSet.bid_strategy,
                                        targeting: adSet.targeting,
                                        start_time: adSet.start_time,
                                        end_time: adSet.end_time,
                                        optimization_goal: adSet.optimization_goal,
                                        billing_event: adSet.billing_event,
                                        destination_type: adSet.destination_type,
                                        learning_stage: adSet.learning_stage_info?.status,
                                        effective_status: adSet.effective_status,
                                        updated_at: new Date().toISOString()
                                    }, { onConflict: "company_id,external_id" });

                                if (adSetError) {
                                    console.error("AdSet upsert error:", adSetError);
                                    itemsFailed++;
                                } else {
                                    itemsSynced++;
                                }
                            }
                        }
                    }

                    // 3. Fetch ads/creatives for each ad set
                    const { data: localAdSets } = await supabase
                        .from("ad_sets")
                        .select("id, external_id, campaign_id")
                        .eq("company_id", integration.company_id)
                        .eq("platform", "meta");

                    for (const localAdSet of localAdSets || []) {
                        const adsUrl = `${META_API_BASE}/${localAdSet.external_id}/ads?fields=id,name,status,creative{id,title,body,image_url,video_id,thumbnail_url,call_to_action_type}&limit=100&access_token=${accessToken}`;
                        const adsRes = await fetch(adsUrl);
                        const adsData = await adsRes.json();

                        if (adsData.data) {
                            for (const ad of adsData.data as MetaAd[]) {
                                const creative = ad.creative;
                                let creativeFormat = "image";
                                if (creative?.video_id) creativeFormat = "video";

                                const { error: adError } = await supabase
                                    .from("creatives")
                                    .upsert({
                                        company_id: integration.company_id,
                                        campaign_id: localAdSet.campaign_id,
                                        ad_set_id: localAdSet.id,
                                        external_id: ad.id,
                                        name: ad.name,
                                        type: "ad",
                                        creative_format: creativeFormat,
                                        platform: "meta",
                                        status: ad.status.toLowerCase(),
                                        headline: creative?.title,
                                        description: creative?.body,
                                        image_url: creative?.image_url || creative?.thumbnail_url,
                                        video_url: creative?.video_id ? `https://www.facebook.com/${creative.video_id}` : null,
                                        call_to_action: creative?.call_to_action_type,
                                        updated_at: new Date().toISOString()
                                    }, { onConflict: "company_id,external_id" });

                                if (adError) {
                                    console.error("Ad upsert error:", adError);
                                    itemsFailed++;
                                } else {
                                    itemsSynced++;
                                }
                            }
                        }
                    }
                }

                // 4. Fetch insights/metrics (always run)
                const today = new Date();
                const thirtyDaysAgo = new Date(today.getTime() - 30 * 24 * 60 * 60 * 1000);
                const dateFormat = (d: Date) => d.toISOString().split("T")[0];

                const insightsFields = [
                    'campaign_id', 'impressions', 'clicks', 'spend', 'ctr', 'cpc', 'cpm', 'actions',
                    'reach', 'frequency', 'unique_clicks', 'unique_ctr',
                    'quality_ranking', 'engagement_rate_ranking', 'conversion_rate_ranking',
                    'video_p25_watched_actions', 'video_p50_watched_actions', 'video_p75_watched_actions', 'video_p100_watched_actions',
                    'website_purchase_roas'
                ].join(',');

                const insightsUrl = `${META_API_BASE}/${accountId}/insights?fields=${insightsFields}&level=campaign&time_range={"since":"${dateFormat(thirtyDaysAgo)}","until":"${dateFormat(today)}"}&time_increment=1&limit=500&access_token=${accessToken}`;
                const insightsRes = await fetch(insightsUrl);
                const insightsData = await insightsRes.json();

                if (insightsData.data) {
                    // Get campaign ID mapping
                    const { data: campaignMap } = await supabase
                        .from("campaigns")
                        .select("id, external_id")
                        .eq("company_id", integration.company_id)
                        .eq("platform", "meta");

                    const extToLocalId = new Map(campaignMap?.map(c => [c.external_id, c.id]) || []);

                    for (const insight of insightsData.data as MetaInsight[]) {
                        const localCampaignId = extToLocalId.get(insight.campaign_id);
                        if (!localCampaignId) continue;

                        // Extract conversions from actions
                        let conversions = 0;
                        if (insight.actions) {
                            const convAction = insight.actions.find(a =>
                                a.action_type === "purchase" ||
                                a.action_type === "lead" ||
                                a.action_type === "complete_registration"
                            );
                            if (convAction) conversions = parseInt(convAction.value);
                        }

                        // Helper to get value from action list
                        const getActionValue = (actions?: Array<{ value: string }>) => {
                            if (!actions || actions.length === 0) return 0;
                            return parseFloat(actions[0].value) || 0;
                        };

                        const { error: metricError } = await supabase
                            .from("campaign_metrics")
                            .upsert({
                                company_id: integration.company_id,
                                campaign_id: localCampaignId,
                                date: insight.date_start,
                                impressions: parseInt(insight.impressions) || 0,
                                clicks: parseInt(insight.clicks) || 0,
                                spend: parseFloat(insight.spend) || 0,
                                ctr: parseFloat(insight.ctr || "0"),
                                cpc: parseFloat(insight.cpc || "0"),
                                cpm: parseFloat(insight.cpm || "0"),
                                conversions,
                                reach: parseInt(insight.reach || "0"),
                                frequency: parseFloat(insight.frequency || "0"),
                                unique_clicks: parseInt(insight.unique_clicks || "0"),
                                unique_ctr: parseFloat(insight.unique_ctr || "0"),
                                quality_ranking: insight.quality_ranking,
                                engagement_rate_ranking: insight.engagement_rate_ranking,
                                conversion_rate_ranking: insight.conversion_rate_ranking,
                                video_p25: getActionValue(insight.video_p25_watched_actions),
                                video_p50: getActionValue(insight.video_p50_watched_actions),
                                video_p75: getActionValue(insight.video_p75_watched_actions),
                                video_p100: getActionValue(insight.video_p100_watched_actions),
                                website_purchase_roas: getActionValue(insight.website_purchase_roas),
                                created_at: new Date().toISOString()
                            }, { onConflict: "company_id,campaign_id,date" });

                        if (metricError) {
                            console.error("Metric upsert error:", metricError);
                            itemsFailed++;
                        } else {
                            itemsSynced++;
                        }
                    }
                }

                // Update last_sync_at on integration
                await supabase
                    .from("integrations")
                    .update({ last_sync_at: new Date().toISOString() })
                    .eq("id", integration.id);

                // Record sync history
                await supabase.from("sync_history").insert({
                    company_id: integration.company_id,
                    integration_id: integration.id,
                    sync_type,
                    status: itemsFailed > 0 ? "completed_with_errors" : "completed",
                    items_synced: itemsSynced,
                    items_failed: itemsFailed,
                    started_at: syncStartTime,
                    completed_at: new Date().toISOString()
                });

                results.push({
                    integration_id: integration.id,
                    account_id: integration.account_id,
                    items_synced: itemsSynced,
                    items_failed: itemsFailed,
                    status: "success"
                });

            } catch (syncError) {
                console.error("Sync error for integration:", integration.id, syncError);

                await supabase.from("sync_history").insert({
                    company_id: integration.company_id,
                    integration_id: integration.id,
                    sync_type,
                    status: "failed",
                    items_synced: itemsSynced,
                    items_failed: itemsFailed,
                    error_message: String(syncError),
                    started_at: syncStartTime,
                    completed_at: new Date().toISOString()
                });

                results.push({
                    integration_id: integration.id,
                    account_id: integration.account_id,
                    status: "error",
                    error: String(syncError)
                });
            }
        }

        return new Response(
            JSON.stringify({ success: true, results }),
            { headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );

    } catch (error) {
        console.error("Unexpected error:", error);
        return new Response(
            JSON.stringify({ error: "Internal server error" }),
            { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
    }
});
